import React from 'react';
import ReactDOM from 'react-dom/client';
import { HashRouter } from 'react-router-dom';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <HashRouter>
      <App />
    </HashRouter>
  </React.StrictMode>
);

export enum Category {
  ALL = 'All',
  HALL = 'Hall',
  KITCHEN = 'Kitchen',
  BEDROOM = 'Bedroom',
  BATHROOM = 'Bathroom',
  BALCONY = 'Balcony'
}

export interface Project {
  id: string;
  title: string;
  category: Category;
  image: string;
}

export interface Service {
  title: string;
  description: string;
  image: string;
}

import React, { useState, useEffect } from 'react';

interface Props {
  value: number;
  suffix?: string;
  duration?: number;
}

export const AnimatedNumber: React.FC<Props> = ({ value, suffix = '', duration = 2000 }) => {
  const [count, setCount] = useState(0);

  useEffect(() => {
    let startTime: number | null = null;
    const step = (timestamp: number) => {
      if (!startTime) startTime = timestamp;
      const progress = Math.min((timestamp - startTime) / duration, 1);
      setCount(Math.floor(progress * value));
      if (progress < 1) {
        window.requestAnimationFrame(step);
      }
    };
    window.requestAnimationFrame(step);
  }, [value, duration]);

  return <span>{count}{suffix}</span>;
};

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const links = [
    { name: 'Home', path: '/' },
    { name: 'About', path: '/about' },
    { name: 'Services', path: '/services' },
    { name: 'Projects', path: '/projects' },
    { name: 'Contact', path: '/contact' },
  ];

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-500 ${isScrolled ? 'bg-[#0E0E0E]/80 backdrop-blur-xl py-4 border-b border-white/5' : 'bg-transparent py-8'}`}>
      <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
        <Link to="/" className="group flex flex-col">
          <span className="text-2xl font-black tracking-tighter text-white">DESIGN BLOCKS</span>
          <span className="text-[10px] tracking-[0.2em] uppercase text-blue-400 font-bold group-hover:text-green-400 transition-colors">Interior Design</span>
        </Link>
        <div className="hidden md:flex gap-10">
          {links.map(link => (
            <Link 
              key={link.path} 
              to={link.path} 
              className={`text-sm font-medium tracking-widest uppercase transition-all hover:text-blue-400 ${location.pathname === link.path ? 'text-green-400' : 'text-gray-400'}`}
            >
              {link.name}
            </Link>
          ))}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { PROJECTS } from '../constants';
import { Category, Project } from '../types';

const Projects: React.FC = () => {
  const [filter, setFilter] = useState<Category>(Category.ALL);
  const [filteredProjects, setFilteredProjects] = useState<Project[]>(PROJECTS);
  const [isAnimate, setIsAnimate] = useState(false);

  const categories = Object.values(Category);

  useEffect(() => {
    setIsAnimate(false);
    setTimeout(() => {
      if (filter === Category.ALL) {
        setFilteredProjects(PROJECTS);
      } else {
        setFilteredProjects(PROJECTS.filter(p => p.category === filter));
      }
      setIsAnimate(true);
    }, 300);
  }, [filter]);

  return (
    <div className="min-h-screen pt-40 pb-20 px-6">
      <div className="max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row justify-between items-end gap-10 mb-20">
          <div className="space-y-4">
            <h1 className="text-7xl font-black text-white tracking-tighter uppercase leading-none">Project<br /><span className="text-green-400">Index</span></h1>
            <p className="text-gray-500 max-w-md uppercase tracking-[0.2em] text-[10px] font-bold">Selected works from the visioncraft archives</p>
          </div>

          {/* Filter Bar */}
          <div className="flex flex-wrap gap-2 glass p-2 rounded-xl border border-white/5">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-6 py-2 rounded-lg text-[10px] uppercase font-bold tracking-widest transition-all ${filter === cat ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>

        <div className={`grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 transition-opacity duration-500 ${isAnimate ? 'opacity-100' : 'opacity-0'}`}>
          {filteredProjects.map((project) => (
            <div 
              key={project.id} 
              className="group relative aspect-[4/5] glass rounded-3xl overflow-hidden border border-white/5 hover:border-blue-500/50 transition-all"
            >
              <img 
                src={project.image} 
                alt={project.title} 
                className="absolute inset-0 w-full h-full object-cover grayscale opacity-60 group-hover:grayscale-0 group-hover:opacity-100 group-hover:scale-110 transition-all duration-1000"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
              <div className="absolute inset-x-0 bottom-0 p-10 transform translate-y-full group-hover:translate-y-0 transition-transform duration-500">
                <span className="text-[10px] uppercase tracking-widest text-green-400 font-bold mb-2 block">{project.category}</span>
                <h3 className="text-3xl font-black text-white mb-6 uppercase tracking-tighter">{project.title}</h3>
                <div className="h-0.5 w-0 group-hover:w-full bg-blue-500 transition-all duration-700"></div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Projects;

